    "source_fingerprint": "{\"title\":\"Dialoog: Di Hotel\",\"order_index\":2,\"content\":{\"type\":\"dialogue\",\"lines\":[{\"text\":\"Selamat siang, Mas. Kamar saya nomor berapa?\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Nomor 215, Bu. Di lantai 2.\",\"speaker\":\"Mas Wawan\",\"translation\":\"\"},{\"text\":\"Paspor Ibu di mana? Saya harus isi formulir hotel.\",\"speaker\":\"Mas Wawan\",\"translation\":\"\"},{\"text\":\"Ini paspor saya. Kunci saya di mana?\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Kunci yang kecil dan kuning ini kunci Ibu, silakan!\",\"speaker\":\"Mas Wawan\",\"translation\":\"\"},{\"text\":\"Kamar saya bagus. Kamar mandi ada di mana?\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Di sini, Bu. Handuk, sabun dan sikat gigi ada. Di situ bak air.\",\"speaker\":\"Mas Wawan\",\"translation\":\"\"},{\"text\":\"Air di bak untuk mandi.\",\"speaker\":\"Mas Wawan\",\"translation\":\"\"},{\"text\":\"Oke, terima kasih, ya Mas!\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Mas, saya ingin makan. Apa makanan yang enak?\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Oo, apa Ibu suka ayam pedas, nasi kuning dan lauk?\",\"speaker\":\"Mas Imran\",\"translation\":\"\"},{\"text\":\"Eeh... suka, tetapi saya ingin makan sate kambing, gado-gado dan nasi putih.\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"},{\"text\":\"Tambah krupuk juga dan segelas air putih, ya Mas.\",\"speaker\":\"Ibu Dewi\",\"translation\":\"\"}]}}"
