    "source_fingerprint": "{\"title\":\"Grammatica: YANG - Constructie\",\"order_index\":3,\"content\":{\"type\":\"grammar\",\"categories\":[{\"rules\":[\"Yang koppelt als betrekkelijk voornaamwoord een bijzin aan het voorgaande zelfstandig naamwoord.\",\"Yang staat altijd direct na het woord of de woordgroep waarnaar verwezen wordt.\",\"Na samengestelde zelfstandige naamwoorden (kamar mandi, tempat tidur) is yang verplicht.\",\"Na een bezittelijk voornaamwoord dient een bijvoeglijk naamwoord ook voorafgegaan te worden door yang.\"],\"title\":\"Yang als betrekkelijk voornaamwoord (die/dat)\",\"examples\":[{\"dutch\":\"Een banaan die te oud is, is niet lekker\",\"indonesian\":\"Pisang yang terlalu tua tidak enak\"},{\"dutch\":\"Dit is de Nederlander die in Bogor woont\",\"indonesian\":\"Ini orang Belanda yang tinggal di Bogor\"},{\"dutch\":\"Mijn kleine fiets is verdwenen\",\"indonesian\":\"Sepeda saya yang kecil hilang\"}]},{\"rules\":[\"Yang kan bijvoeglijke naamwoorden, werkwoorden en andere woordsoorten omzetten naar zelfstandige naamwoorden.\",\"Vergelijkbaar met het Nederlandse 'de...' of 'degenen die...'.\"],\"title\":\"Yang maakt zelfstandige naamwoorden (nominalisering)\",\"examples\":[{\"dutch\":\"De dure (dingen) zijn mooi\",\"indonesian\":\"Yang mahal bagus\"},{\"dutch\":\"De grote is lekker\",\"indonesian\":\"Yang besar enak\"},{\"dutch\":\"Degenen die slapen zijn talrijk\",\"indonesian\":\"Yang tidur banyak\"},{\"dutch\":\"Degenen die naar de winkel willen moeten een taxi nemen\",\"indonesian\":\"Yang mau ke toko harus naik taksi\"},{\"dutch\":\"Deze twee zijn schoon\",\"indonesian\":\"Yang dua ini bersih\"}]},{\"rules\":[\"Yang vóór één bijvoeglijk naamwoord geeft nadruk aan dat eigenschap.\",\"Vergelijkbaar met het cursief zetten van een woord in het Nederlands.\"],\"title\":\"Yang bij één bijvoeglijk naamwoord (nadruk)\",\"examples\":[{\"dutch\":\"Het GROTE huis (nadruk op groot)\",\"indonesian\":\"Rumah yang besar\"},{\"dutch\":\"De SCHONE lepel\",\"indonesian\":\"Sendok yang bersih\"},{\"dutch\":\"De KLEINE stoel\",\"indonesian\":\"Kursi yang kecil\"},{\"dutch\":\"De WITTE badkamer\",\"indonesian\":\"Kamar mandi yang putih\"}]},{\"rules\":[\"Bij ongelijke nadruk (één eigenschap benadrukt): [znw] [bijv.nw.] yang [benadrukt bijv.nw.]\",\"Bij gelijke nadruk (beide eigenschappen even belangrijk): [znw] yang [bijv.nw.] dan [bijv.nw.]\"],\"title\":\"Yang bij twee bijvoeglijke naamwoorden\",\"examples\":[{\"dutch\":\"Het GELE grote huis (geel benadrukt)\",\"indonesian\":\"Rumah besar yang kuning\"},{\"dutch\":\"De schone kleine lepel (schoon benadrukt)\",\"indonesian\":\"Sendok kecil yang bersih\"},{\"dutch\":\"Het grote en gele huis (gelijke nadruk)\",\"indonesian\":\"Rumah yang besar dan kuning\"},{\"dutch\":\"De witte, zware kamerdeur (gelijke nadruk)\",\"indonesian\":\"Pintu kamar yang putih dan berat\"}]},{\"rules\":[\"Ada yang... betekent 'er zijn er die...' of 'sommigen..., anderen...'.\",\"Wordt gebruikt om een groep te verdelen of een deel aan te duiden.\"],\"title\":\"Ada yang... — er zijn er die...\",\"examples\":[{\"dutch\":\"Er zijn er die uit Nederland komen en er zijn er die uit Duitsland komen\",\"indonesian\":\"Ada yang dari negeri Belanda dan ada yang dari negeri Jerman\"}]}]}}"
